<template>
  <div class="flow-container">
    <div class="config-panel">
      <h3>流程配置</h3>
      <div class="node-list">
        <div v-for="node in nodes" :key="node.id" class="node-config-item">
          <input v-model="node.label" @change="updateNodeLabel(node)" />
          <button @click="removeNode(node.id)">删除</button>
        </div>
      </div>
      <button @click="addNewNode">➕ 添加步骤</button>
      <hr />
      <div>
        <h4>添加连线</h4>
        <select v-model="newEdgeSource">
          <option disabled value="">源节点</option>
          <option v-for="n in nodes" :key="n.id" :value="n.id">{{ n.label }}</option>
        </select>
        <select v-model="newEdgeTarget">
          <option disabled value="">目标节点</option>
          <option v-for="n in nodes" :key="n.id" :value="n.id">{{ n.label }}</option>
        </select>
        <button @click="addEdge">添加连线</button>
      </div>
      <hr />
      <button @click="fitView">适应画布</button>
      <button @click="exportFlow">导出 JSON</button>
    </div>

    <!-- 流程图核心区域 -->
    <div class="vue-flow-wrapper">
      <VueFlow
        v-model:nodes="nodes"
        v-model:edges="edges"
        :fit-view-on-init="true"
        :default-viewport="{ zoom: 1.2 }"
        :min-zoom="0.5"
        :max-zoom="2"
        @node-click="onNodeClick"
        @edge-click="onEdgeClick"
        @connect="onConnect"
      >
        <template #node-default="props">
          <div class="custom-node">
            <Handle type="target" :position="Position.Top" />
            <div>
              {{ props.data.label }}
            </div>
            <Handle type="source" :position="Position.Bottom" />
            <!-- <Handle type="source" :position="Position.Left" class="handle-left" /> -->
            <!-- <Handle type="source" :position="Position.Right" class="handle-right" /> -->
          </div>
        </template>

        <template #node-input="props">
          <div>
            <div>
              {{ props.data.label }}
            </div>
            <Handle type="source" :position="Position.Bottom" />
          </div>
        </template>

        <template #node-output="props">
          <div class="custom-node output-node">
            <Handle type="target" :position="Position.Top" class="handle-top" />
            <div class="node-content">
              {{ props.data.label }}
            </div>
          </div>
        </template>

        <Background pattern-color="#aaa" :gap="20" />
        <Controls />
      </VueFlow>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { VueFlow, useVueFlow, Position, Handle } from '@vue-flow/core'
import { Background } from '@vue-flow/background'
import { Controls } from '@vue-flow/controls'
import '@vue-flow/core/dist/style.css'
import '@vue-flow/controls/dist/style.css'
// 初始节点：账号申请流程典型步骤
const initialNodes = [
  {
    id: '1',
    label: '填写申请信息',
    position: { x: 100, y: 100 },
    // type: "default",
    data: { label: '填写申请信息' }
  },
  {
    id: '2',
    label: '主管审批',
    position: { x: 100, y: 250 },
    // type: "default",
    data: { label: '主管审批' }
  },
  {
    id: '3',
    label: '系统创建账号',
    position: { x: 100, y: 400 },
    // type: "default",
    data: { label: '系统创建账号' }
  },
  {
    id: '4',
    label: '权限配置',
    position: { x: 100, y: 550 },
    // type: "default",
    data: { label: '权限配置' }
  },
  {
    id: '5',
    label: '流程结束',
    position: { x: 100, y: 700 },
    // type: "default",
    data: { label: '流程结束' }
  }
]

const initialEdges = [
  { id: 'e1-2', source: '1', target: '2', label: '提交', data: { label: '提交' } },
  { id: 'e2-3', source: '2', target: '3', label: '通过', data: { label: '通过' } },
  {
    id: 'e3-4',
    source: '3',
    target: '4',
    label: '完成创建',
    data: { label: '完成创建' }
  },
  {
    id: 'e4-5',
    source: '4',
    target: '5',
    label: '完成配置',
    data: { label: '完成配置' }
  }
]

const nodes = ref(initialNodes)
const edges = ref(initialEdges)

// 连线辅助变量
const newEdgeSource = ref('')
const newEdgeTarget = ref('')

// 获取 useVueFlow 实例（用于视图控制和手动变更）
const { fitView, addEdges, removeEdges, updateNode, addNodes, removeNodes } = useVueFlow()

// 更新节点标签
function updateNodeLabel(node) {
  updateNode(node.id, { label: node.label })
}

// 删除节点（同时删除关联的边）
function removeNode(nodeId) {
  // 找到所有与该节点相连的边
  const connectedEdges = edges.value.filter(edge => edge.source === nodeId || edge.target === nodeId)
  // 删除这些边
  removeEdges(connectedEdges.map(e => e.id))
  // 删除节点
  removeNodes([nodeId])
}

// 添加新节点（默认在现有节点最下方偏移位置）
function addNewNode() {
  const maxY = Math.max(...nodes.value.map(n => n.position.y), 0)
  const newNodeId = String(Date.now())
  const newNode = {
    id: newNodeId,
    label: '新步骤',
    position: { x: 100, y: maxY + 150 },
    type: 'default',
    data: { label: '新步骤' }
  }
  addNodes([newNode])
}

// 手动添加边
function addEdge() {
  if (!newEdgeSource.value || !newEdgeTarget.value) {
    alert('请选择源节点和目标节点')
    return
  }
  const newEdgeId = `e-${newEdgeSource.value}-${newEdgeTarget.value}`
  // 避免重复连线
  if (edges.value.some(e => e.id === newEdgeId)) {
    alert('连线已存在')
    return
  }
  addEdges([
    {
      id: newEdgeId,
      source: newEdgeSource.value,
      target: newEdgeTarget.value,
      label: '新连线'
    }
  ])
  newEdgeSource.value = ''
  newEdgeTarget.value = ''
}

// 导出流程图配置（JSON）
function exportFlow() {
  const flowData = {
    nodes: nodes.value,
    edges: edges.value
  }
  console.log('导出配置:', JSON.stringify(flowData, null, 2))
  alert('配置已导出，请查看控制台')
}

// 交互事件（可扩展）
function onNodeClick({ node }) {
  console.log('点击节点:', node.label)
}

function onEdgeClick({ edge }) {
  console.log('点击连线:', edge.label)
}

// 拖拽连线完成时的回调（自动添加到 edges）
function onConnect(connection) {
  console.log('新连线:', connection)
  // connection 包含 source, target, sourceHandle, targetHandle
  // 直接添加到边集合中即可
  addEdges([
    {
      id: `e-${connection.source}-${connection.target}`,
      ...connection,
      label: '新连线'
    }
  ])
}
</script>

